The reference solution of that problem in Typescript is 
function solve(edges: number[][], online: boolean[], k: number): number {
    const n = online.length;
    const adj = new Array(n).fill(0).map(() => []);
    const inDegree = new Array(n).fill(0);

    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
        inDegree[v]++;
    }

    const queue: number[] = [];
    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) {
            queue.push(i);
        }
    }

    const topologicalOrder: number[] = [];
    while (queue.length > 0) {
        const u = queue.shift()!;
        topologicalOrder.push(u);
        for (const [v, _] of adj[u]) {
            inDegree[v]--;
            if (inDegree[v] === 0) {
                queue.push(v);
            }
        }
    }

    let maxEdgeCost = 0;
    for (const [u, v, cost] of edges) {
        if (cost > maxEdgeCost) {
            maxEdgeCost = cost;
        }
    }

    let low = 0;
    let high = maxEdgeCost;
    let answer = -1;

    function check(x: number): boolean {
        const dist = new Array(n).fill(Infinity);
        dist[0] = 0;
        for (const u of topologicalOrder) {
            if (!online[u]) continue;
            for (const [v, c] of adj[u]) {
                if (c >= x && online[v]) {
                    if (dist[u] + c < dist[v]) {
                        dist[v] = dist[u] + c;
                    }
                }
            }
        }
        return dist[n - 1] <= k;
    }

    while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        if (check(mid)) {
            answer = mid;
            low = mid + 1;
        } else {
            high = mid - 1;
        }
    }

    return answer;
}

